```tsx
import React, { useState, useEffect } from 'react';
import { Application, University, UserProfile } from '../types';

interface ApplicationFormModalProps {
  isOpen: boolean;
  onClose: () => void;
  application: Application | null;
  university: University | null; // Fallback if creating new
  userProfile: UserProfile;
  onSave: (app: Application) => void;
}

const STEPS = [
  { id: 1, title: 'Personal Info' },
  { id: 2, title: 'Academics' },
  { id: 3, title: 'Essay' },
  { id: 4, title: 'Review' }
];

const ApplicationFormModal: React.FC<ApplicationFormModalProps> = ({ 
  isOpen, 
  onClose, 
  application, 
  university,
  userProfile,
  onSave 
}) => {
  // Initialize state
  const [currentStep, setCurrentStep] = useState(1);
  const [formData, setFormData] = useState<Application['formData']>({
    personal: {},
    academic: {},
    essay: ''
  });

  // Load existing data when modal opens
  useEffect(() => {
    if (isOpen) {
      if (application) {
        setCurrentStep(application.currentStep || 1);
        setFormData(application.formData || { personal: {}, academic: {}, essay: '' });
      } else {
        // Pre-fill from user profile for new applications
        setFormData({
          personal: {
            fullName: userProfile.name || '',
            email: userProfile.email || '',
          },
          academic: {
            major: userProfile.fieldOfStudy || ''
          },
          essay: ''
        });
        setCurrentStep(1);
      }
    }
  }, [isOpen, application, userProfile, university]);

  if (!isOpen) return null;

  const targetUni = application?.university || university;
  if (!targetUni) return null;

  const handleSaveAndClose = () => {
    const progress = Math.round(((currentStep - 1) / STEPS.length) * 100);

    const updatedApp: Application = {
      id: application?.id || Date.now().toString(),
      university: targetUni,
      status: 'draft',
      lastUpdated: new Date(),
      progress: progress === 0 ? 10 : progress, // Minimum 10% if started
      currentStep,
      formData
    };

    onSave(updatedApp);
    onClose();
  };

  const handleSubmit = () => {
    const updatedApp: Application = {
      id: application?.id || Date.now().toString(),
      university: targetUni,
      status: 'submitted',
      submittedDate: new Date(),
      lastUpdated: new Date(),
      progress: 100,
      currentStep: 4,
      formData
    };

    onSave(updatedApp);
    onClose();
  };

  const updateField = (section: 'personal' | 'academic', field: string, value: string) => {
    setFormData(prev => ({
      ...prev,
      [section]: { ...prev[section], [field]: value }
    }));
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm">
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-2xl max-h-[90vh] flex flex-col overflow-hidden animate-fade-in">

        {/* Header */}
        <div className="bg-brand-600 p-6 text-white flex justify-between items-start">
          <div>
            <p className="text-brand-100 text-sm font-medium uppercase tracking-wider mb-1">Application For</p>
            <h2 className="text-2xl font-bold">{targetUni.name}</h2>
          </div>
          <button onClick={handleSaveAndClose} className="text-brand-100 hover:text-white bg-white/10 hover:bg-white/20 p-2 rounded-lg transition-colors">
             <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" className="w-5 h-5">
              <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
        </div>

        {/* Steps Progress */}
        <div className="bg-slate-50 border-b border-slate-200 px-6 py-4">
          <div className="flex items-center justify-between relative">
             {/* Progress Line Background */}
             <div className="absolute left-0 right-0 top-1/2 h-0.5 bg-slate-200 -z-10" />

             {STEPS.map((step, idx) => {
                const isCompleted = step.id < currentStep;
                const isCurrent = step.id === currentStep;
                return (
                  <div key={step.id} className="flex flex-col items-center gap-2 bg-slate-50 px-2">
                    <div className={`w-8 h-8 rounded-full flex items-center justify-center text-xs font-bold transition-colors border-2
                      ${isCompleted ? 'bg-green-500 border-green-500 text-white' : 
                        isCurrent ? 'bg-white border-brand-600 text-brand-600' : 
                        'bg-white border-slate-300 text-slate-400'}
                    `}>
                      {isCompleted ? (
                        <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor" className="w-4 h-4">
                          <path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" />
                        </svg>
                      ) : step.id}
                    </div>
                    <span className={`text-xs font-medium ${isCurrent ? 'text-brand-700' : 'text-slate-500'}`}>{step.title}</span>
                  </div>
                );
             })}
          </div>
        </div>

