                className="text-slate-500 font-bold text-sm hover:text-brand-600 transition-colors"
            >
                Save & Exit
            </button>

            <div className="flex gap-3">
                {currentStep > 1 && (
                    <button 
                        onClick={() => setCurrentStep(prev => prev - 1)}
                        className="px-6 py-2.5 rounded-xl border border-slate-200 text-slate-600 font-bold hover:bg-slate-50 transition-colors"
                    >
                        Back
                    </button>
                )}

                {currentStep < 4 ? (
                    <button 
                        onClick={() => setCurrentStep(prev => prev + 1)}
                        className="px-8 py-2.5 rounded-xl bg-brand-600 text-white font-bold shadow-lg shadow-brand-200 hover:bg-brand-700 transition-all"
                    >
                        Next Step
                    </button>
                ) : (
                    <button 
                        onClick={handleSubmit}
                        className="px-8 py-2.5 rounded-xl bg-green-600 text-white font-bold shadow-lg shadow-green-200 hover:bg-green-700 transition-all flex items-center gap-2"
                    >
                        Submit Application
                        <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor" className="w-4 h-4">
                            <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.857-9.809a.75.75 0 00-1.214-.882l-3.483 4.79-1.88-1.88a.75.75 0 10-1.06 1.061l2.5 2.5a.75.75 0 001.137-.089l4-5.5z" clipRule="evenodd" />
                        </svg>
                    </button>
                )}
            </div>
        </div>
      </div>
    </div>
  );
};

export default ApplicationFormModal;
